CREATE TABLE fleet (
  drone_id TEXT PRIMARY KEY,
  current_location GEOMETRY(Point, 4326),
  battery_pct INT,
  status TEXT,
  last_update TIMESTAMP
);
CREATE INDEX idx_fleet_geom ON fleet USING GIST (current_location);

class DeliveryNode(Node):
    def __init__(self):
        super().__init__('delivery_node')
        self.mission_sub = self.create_subscription(MissionMsg, '/mission', self.mission_cb, 10)
        self.vel_pub = self.create_publisher(Twist, '/mavros/setpoint_velocity/cmd_vel_unstamped', 10)

    def mission_cb(self, msg):
        waypoints = msg.waypoints
        for wp in waypoints:
            self.fly_to(wp)
        self.assess_landing_zone()
        self.land_and_release()
        self.return_home()
